import fs from 'node:fs/promises';
import path from 'node:path';

const root = '/tmp/codexdesktop-tasks/electron43-wcv-linux';
const evidencePath = path.join(root, 'evidence.jsonl');
const metricsPath = path.join(root, 'metrics.json');
const observedAt = new Date().toISOString();

async function fetchText(url, opts = {}) {
  const res = await fetch(url, { headers: { 'user-agent': 'codex-research/1.0', accept: opts.accept || 'text/html,application/json,text/plain' } });
  const text = await res.text();
  return { url, status: res.status, ok: res.ok, text };
}

function stripHtml(html) {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\s+/g, ' ')
    .trim();
}

function snippet(text, terms, len = 900) {
  const lower = text.toLowerCase();
  let idx = -1;
  for (const term of terms) {
    idx = lower.indexOf(term.toLowerCase());
    if (idx >= 0) break;
  }
  if (idx < 0) idx = 0;
  const start = Math.max(0, idx - Math.floor(len / 3));
  return text.slice(start, start + len).replace(/\s+/g, ' ').trim();
}

async function githubSearch(q, limit = 8) {
  const url = `https://api.github.com/search/issues?q=${encodeURIComponent(q)}&sort=updated&order=desc&per_page=${limit}`;
  const { status, text } = await fetchText(url, { accept: 'application/vnd.github+json' });
  let json = {};
  try { json = JSON.parse(text); } catch {}
  return { status, url, items: json.items || [], total_count: json.total_count || 0 };
}

function classifyApplicability(item) {
  const body = `${item.title || ''}\n${item.body || ''}`;
  if (/\b43(?:\.|$)/.test(body) || /Electron\s+43/i.test(body)) return 'confirmed';
  if (/\b(37|38|39|40|41|42)(?:\.|$)/.test(body) || /Electron\s+(37|38|39|40|41|42)/i.test(body)) return 'likely';
  return 'unknown';
}

const records = [];
const diagnostics = [];

function add(record) {
  records.push({
    observedAt,
    ...record
  });
}

const officialTargets = [
  ['WebContentsView API', 'https://www.electronjs.org/docs/latest/api/web-contents-view'],
  ['BrowserView deprecation', 'https://www.electronjs.org/docs/latest/api/browser-view'],
  ['BaseWindow API', 'https://www.electronjs.org/docs/latest/api/base-window'],
  ['Electron releases', 'https://releases.electronjs.org/releases/stable']
];

for (const [title, url] of officialTargets) {
  try {
    const out = await fetchText(url);
    const text = out.text.trim().startsWith('{') || out.text.trim().startsWith('[') ? out.text : stripHtml(out.text);
    diagnostics.push({ url, status: out.status, bytes: out.text.length });
    add({
      source: 'Electron official',
      title,
      url,
      sourceType: 'primary',
      reportedVersion: title === 'Electron releases' ? 'stable releases feed' : 'latest docs',
      targetVersionApplicability: title === 'Electron releases' ? 'confirmed' : 'not-applicable',
      platform: 'cross-platform',
      status: out.ok ? 'fetched' : `http ${out.status}`,
      claim: snippet(text, ['WebContentsView', 'deprecated', 'BaseWindow', '43.0.0'], 1000),
      evidenceStrength: out.ok ? 'high' : 'low',
      caveat: title.includes('latest') ? 'Latest docs may move after Electron 43.' : ''
    });
  } catch (error) {
    diagnostics.push({ url, error: String(error) });
  }
}

const queries = [
  'repo:electron/electron WebContentsView Linux performance',
  'repo:electron/electron WebContentsView Linux crash OR freeze OR stability',
  'repo:electron/electron WebContentsView BrowserView linux',
  'repo:electron/electron BaseWindow WebContentsView linux'
];

for (const q of queries) {
  try {
    const result = await githubSearch(q, 10);
    diagnostics.push({ query: q, status: result.status, total_count: result.total_count, url: result.url });
    for (const item of result.items.slice(0, 6)) {
      const body = `${item.title || ''}\n${item.body || ''}`;
      if (!/WebContentsView|BrowserView|BaseWindow|linux|performance|crash|freeze|stability/i.test(body)) continue;
      add({
        source: 'GitHub electron/electron',
        title: item.title,
        url: item.html_url,
        sourceType: 'firsthand',
        reportedVersion: (body.match(/Electron(?:\s+Version)?:?\s*v?([0-9][0-9.]+)/i) || body.match(/\belectron\s+v?([0-9][0-9.]+)/i) || [])[1] || 'not stated',
        targetVersionApplicability: classifyApplicability(item),
        platform: /linux|ubuntu|fedora|arch|wayland|x11/i.test(body) ? 'Linux mentioned' : 'not specified',
        status: item.state,
        claim: snippet(body, ['WebContentsView', 'BrowserView', 'linux', 'performance', 'crash', 'freeze'], 1000),
        evidenceStrength: item.comments > 0 ? 'medium' : 'low',
        caveat: 'GitHub search result; applicability is based on issue text and may need manual version confirmation.'
      });
    }
  } catch (error) {
    diagnostics.push({ query: q, error: String(error) });
  }
}

await fs.writeFile(evidencePath, records.map(r => JSON.stringify(r)).join('\n') + '\n');
await fs.writeFile(metricsPath, JSON.stringify({ ok: true, records: records.length, diagnostics }, null, 2));

console.log(JSON.stringify({
  ok: true,
  records: records.length,
  gaps: records.filter(r => r.sourceType === 'firsthand').length ? [] : ['No first-hand GitHub reports captured'],
  artifacts: { evidence: evidencePath, metrics: metricsPath },
  durationMs: 0
}));

import fs from 'node:fs/promises';
import path from 'node:path';

const root = '/tmp/codexdesktop-tasks/electron43-wcv-linux';
const evidencePath = path.join(root, 'evidence.jsonl');
const observedAt = new Date().toISOString();

async function gh(url) {
  const res = await fetch(url, { headers: { 'user-agent': 'codex-research/1.0', accept: 'application/vnd.github+json' } });
  const text = await res.text();
  return { status: res.status, json: JSON.parse(text) };
}

function snippet(text, terms, len = 1200) {
  const lower = text.toLowerCase();
  let idx = -1;
  for (const term of terms) {
    idx = lower.indexOf(term.toLowerCase());
    if (idx >= 0) break;
  }
  if (idx < 0) idx = 0;
  const start = Math.max(0, idx - Math.floor(len / 4));
  return text.slice(start, start + len).replace(/\s+/g, ' ').trim();
}

const issueNumbers = [50535, 45864, 44914, 47990, 49315, 51338, 51769];
const records = [];

for (const n of issueNumbers) {
  const issue = await gh(`https://api.github.com/repos/electron/electron/issues/${n}`);
  const comments = await gh(`https://api.github.com/repos/electron/electron/issues/${n}/comments?per_page=20`);
  const body = `${issue.json.title}\n${issue.json.body || ''}\n${(comments.json || []).map(c => c.body).join('\n---comment---\n')}`;
  const version = (body.match(/Electron(?:\s+Version)?:?\s*v?=?([0-9][0-9.\-a-z]+)/i) || [])[1] || 'not stated';
  records.push({
    observedAt,
    source: 'GitHub electron/electron expanded',
    title: issue.json.title,
    url: issue.json.html_url,
    sourceType: 'firsthand',
    reportedVersion: version,
    targetVersionApplicability: /\b43\b|43\./.test(body) ? 'confirmed' : /\b(40|41|42)\b|40\.|41\.|42\./.test(body) ? 'likely' : 'unknown',
    platform: /linux|ubuntu|fedora|wayland|xorg|x11/i.test(body) ? 'Linux mentioned' : 'not specified',
    status: issue.json.state,
    claim: snippet(body, ['Actual Behavior', 'Wayland', 'Linux', 'WebContentsView', 'BaseWindow', 'paintWhenInitiallyHidden'], 1400),
    evidenceStrength: comments.json?.length ? 'medium' : 'low',
    caveat: 'Expanded issue/comments via GitHub API; not a local reproduction.'
  });
}

const rel = await gh('https://api.github.com/repos/electron/electron/releases?per_page=20');
for (const r of rel.json.filter(r => /^v43\./.test(r.tag_name))) {
  records.push({
    observedAt,
    source: 'GitHub electron/electron releases',
    title: r.name || r.tag_name,
    url: r.html_url,
    sourceType: 'primary',
    reportedVersion: r.tag_name,
    targetVersionApplicability: 'confirmed',
    platform: 'cross-platform',
    status: r.prerelease ? 'prerelease' : 'released',
    claim: snippet(r.body || '', ['Features', 'Fixes', 'WebContentsView', 'Linux', 'Wayland', 'Chromium'], 1400),
    evidenceStrength: 'high',
    caveat: 'Release notes are authoritative for included changes but not a guarantee for application-specific stability.'
  });
}

await fs.appendFile(evidencePath, records.map(r => JSON.stringify(r)).join('\n') + '\n');
console.log(JSON.stringify({ ok: true, appended: records.length, evidence: evidencePath }));
